transform_js:
const data = [];
rawData.rows.forEach(r => {
  data.push({ name: r.name, value: r.value });
});
// 見栄えを良くするために値の降順で並び替え
data.sort((a, b) => b.value - a.value);
transformedData = data;

echarts_js:
option = {
  title: {
    text: 'Causes of Mortality (Rose Diagram)',
    left: 'center'
  },
  tooltip: {
    trigger: 'item',
    formatter: '{a} <br/>{b} : {c} ({d}%)'
  },
  legend: {
    left: 'center',
    top: 'bottom',
    data: transformedData.map(d => d.name)
  },
  toolbox: {
    show: true,
    feature: {
      mark: { show: true },
      dataView: { show: true, readOnly: false },
      restore: { show: true },
      saveAsImage: { show: true }
    }
  },
  series: [
    {
      name: 'Cause of Death',
      type: 'pie',
      radius: [20, '80%'],
      center: ['50%', '50%'],
      // これがナイチンゲールローズにするためのオプション
      roseType: 'radius',
      itemStyle: {
        borderRadius: 5,
        shadowBlur: 10,
        shadowColor: 'rgba(0, 0, 0, 0.2)'
      },
      label: {
         show: true,
         formatter: '{b}'
      },
      data: transformedData
    }
  ]
};
